<?php
require_once __DIR__ . '/../config/database.php'; require_once __DIR__ . '/../includes/functions.php'; requireLogin(); $userId=(int)$_SESSION['user_id']; $userName=$_SESSION['user_name']??'Explorer'; $message=getFlash('simaksi_ok');$error='';
if($_SERVER['REQUEST_METHOD']==='POST'){ $mountainId=(int)($_POST['mountain_id']??0);$trailId=(int)($_POST['trail_id']??0);$nik=trim($_POST['nik']??'');$naik=trim($_POST['tanggal_naik']??'');$turun=trim($_POST['tanggal_turun']??'');$jumlah=(int)($_POST['jumlah_peserta']??1);$setuju=isset($_POST['setuju_peraturan'])?1:0; if($mountainId<=0||$nik===''||$naik===''||$turun===''||!$setuju)$error='Lengkapi data wajib dan centang persetujuan peraturan.'; elseif(strtotime($turun)<strtotime($naik))$error='Tanggal turun tidak boleh sebelum tanggal naik.'; elseif(strtotime($naik)<strtotime(date('Y-m-d')))$error='Tanggal naik tidak boleh di masa lalu.'; else{ $kode='SIM-'.date('Ymd').'-'.strtoupper(substr(md5(uniqid('',true)),0,6)); $stmt=$conn->prepare('INSERT INTO simaksi_applications (kode_simaksi,user_id,mountain_id,trail_id,nama_pengaju,nik,tanggal_naik,tanggal_turun,jumlah_peserta,status_pengajuan,setuju_peraturan) VALUES (?,?,?,?,?,?,?,?,?,"diajukan",?)'); $stmt->bind_param('siiissssii',$kode,$userId,$mountainId,$trailId,$userName,$nik,$naik,$turun,$jumlah,$setuju); if($stmt->execute()){setFlash('simaksi_ok','Pengajuan simaksi berhasil dikirim! Kode: '.$kode);header('Location: '.pageUrl('simaksi'));exit;} else $error='Pengajuan simaksi gagal disimpan.'; }}
$mountains=[];$trails=[];$applications=[]; if($q=$conn->query('SELECT * FROM mountains ORDER BY nama_gunung ASC')){while($r=$q->fetch_assoc())$mountains[]=$r;} if($q=$conn->query('SELECT * FROM trails ORDER BY nama_jalur ASC')){while($r=$q->fetch_assoc())$trails[]=$r;} if($q=$conn->query("SELECT sa.*,m.nama_gunung,t.nama_jalur FROM simaksi_applications sa LEFT JOIN mountains m ON m.id=sa.mountain_id LEFT JOIN trails t ON t.id=sa.trail_id WHERE sa.user_id={$userId} ORDER BY sa.created_at DESC")){while($r=$q->fetch_assoc())$applications[]=$r;} $pageTitle='Pendaftaran Simaksi';$currentPage='simaksi'; include __DIR__.'/../includes/header.php'; include __DIR__.'/../includes/layout_top.php';
?>
<div class="grid lg:grid-cols-[1fr_.85fr] gap-6">
  <div class="editorial-card p-8 md:p-10"><p class="text-xs uppercase tracking-[.3em] text-on-surface-variant font-bold mb-3">Official Permit</p><h3 class="text-3xl font-extrabold mb-2">Daftar Simaksi Pendakian</h3><p class="text-on-surface-variant mb-8">Isi data pengajuan untuk mendapatkan izin pendakian resmi.</p><?php if($message):?><div class="mb-6 rounded-xl bg-green-100 text-green-800 px-4 py-3 font-medium flex items-center gap-3"><span class="material-symbols-outlined">check_circle</span><?=e($message)?></div><?php endif;?><?php if($error):?><div class="mb-6 rounded-xl bg-error-container text-on-error-container px-4 py-3 font-medium"><?=e($error)?></div><?php endif;?><form method="POST" class="grid md:grid-cols-2 gap-6" id="simaksi-form"><div><label class="text-xs uppercase tracking-widest font-bold text-on-surface-variant">Gunung Tujuan</label><select id="mountain_select" name="mountain_id" class="form-input-underline w-full mt-2 py-3" required onchange="filterTrails()"><option value="">Pilih gunung</option><?php foreach($mountains as $m):?><option value="<?= (int)$m['id']?>"><?=e($m['nama_gunung'])?></option><?php endforeach;?></select></div><div><label class="text-xs uppercase tracking-widest font-bold text-on-surface-variant">Jalur</label><select id="trail_select" name="trail_id" class="form-input-underline w-full mt-2 py-3"><option value="0">Pilih jalur</option><?php foreach($trails as $t):?><option value="<?= (int)$t['id']?>" data-mountain="<?= (int)$t['mountain_id'] ?>"><?=e($t['nama_jalur'])?></option><?php endforeach;?></select></div><div><label class="text-xs uppercase tracking-widest font-bold text-on-surface-variant">Nama Pengaju</label><input class="form-input-underline w-full mt-2 py-3" value="<?=e($userName)?>" disabled></div><div><label class="text-xs uppercase tracking-widest font-bold text-on-surface-variant">NIK</label><input name="nik" class="form-input-underline w-full mt-2 py-3" placeholder="3273xxxxxxxxxxxx" maxlength="16" pattern="[0-9]{16}" required></div><div><label class="text-xs uppercase tracking-widest font-bold text-on-surface-variant">Tanggal Naik</label><input type="date" id="tgl_naik" name="tanggal_naik" min="<?=date('Y-m-d')?>" class="form-input-underline w-full mt-2 py-3" required onchange="updateMinTurun()"></div><div><label class="text-xs uppercase tracking-widest font-bold text-on-surface-variant">Tanggal Turun</label><input type="date" id="tgl_turun" name="tanggal_turun" min="<?=date('Y-m-d')?>" class="form-input-underline w-full mt-2 py-3" required></div><div><label class="text-xs uppercase tracking-widest font-bold text-on-surface-variant">Jumlah Peserta</label><input type="number" min="1" max="50" name="jumlah_peserta" value="1" class="form-input-underline w-full mt-2 py-3" required></div><div class="md:col-span-2"><label class="flex items-start gap-3 text-sm text-on-surface-variant"><input type="checkbox" name="setuju_peraturan" class="mt-1 rounded text-primary" required><span>Saya menyetujui seluruh peraturan pendakian, ketentuan kuota, dan kebijakan keselamatan Gunungku.</span></label></div><div class="md:col-span-2"><button class="btn-primary" id="btn-submit-simaksi">Kirim Pengajuan <span class="material-symbols-outlined">arrow_forward</span></button></div></form></div>
  <div class="space-y-6"><div class="editorial-card p-6"><h3 class="text-xl font-extrabold mb-4">Checklist Dokumen</h3><div class="space-y-3"><div class="editorial-card-soft p-4 flex items-center gap-3"><span class="material-symbols-outlined text-primary">badge</span><span>KTP / Identitas Pendaki</span></div><div class="editorial-card-soft p-4 flex items-center gap-3"><span class="material-symbols-outlined text-primary">medical_services</span><span>Surat sehat bila diperlukan</span></div><div class="editorial-card-soft p-4 flex items-center gap-3"><span class="material-symbols-outlined text-primary">rule</span><span>Setuju peraturan pendakian</span></div></div></div><div class="editorial-card p-6"><h3 class="text-xl font-extrabold mb-4">Riwayat Pengajuan</h3><div class="space-y-3 max-h-[420px] overflow-auto custom-scrollbar"><?php if($applications): foreach($applications as $a):?><div class="editorial-card-soft p-4"><div class="flex justify-between gap-3"><div><b><?=e($a['kode_simaksi'])?></b><p class="text-sm text-on-surface-variant"><?=e($a['nama_gunung'])?> • <?=e($a['nama_jalur']??'-')?></p><p class="text-xs mt-2"><?=e(formatDateId($a['tanggal_naik']))?> - <?=e(formatDateId($a['tanggal_turun']))?></p></div><?=statusBadge($a['status_pengajuan'])?></div></div><?php endforeach; else:?><p class="text-on-surface-variant">Belum ada pengajuan.</p><?php endif;?></div></div></div>
</div>
<script>
  function filterTrails() {
    const mountainId = document.getElementById('mountain_select').value;
    const trailSelect = document.getElementById('trail_select');
    const options = trailSelect.querySelectorAll('option');
    options.forEach(opt => {
      if (opt.value === "0") {
        opt.selected = true;
        opt.style.display = 'block';
      } else if (opt.getAttribute('data-mountain') === mountainId) {
        opt.style.display = 'block';
      } else {
        opt.style.display = 'none';
      }
    });
  }
  document.addEventListener('DOMContentLoaded', filterTrails);
  function updateMinTurun(){
    const naik = document.getElementById('tgl_naik').value;
    if(naik) document.getElementById('tgl_turun').min = naik;
  }
  document.getElementById('simaksi-form').addEventListener('submit', function(e){
    const naik = document.getElementById('tgl_naik').value;
    const turun = document.getElementById('tgl_turun').value;
    if(naik && turun && turun < naik){ e.preventDefault(); alert('Tanggal turun tidak boleh sebelum tanggal naik.'); }
  });
</script>
